import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';

const SettingsContext = createContext(null);

const LS_KEYS = {
  reduceMotion: 'gp.reduceMotion',
  muteAudio: 'gp.muteAudio',
};

export function SettingsProvider({ children }) {
  const osPrefersReduced = useMemo(() => {
    if (typeof window === 'undefined' || !window.matchMedia) return false;
    try { return window.matchMedia('(prefers-reduced-motion: reduce)').matches; } catch { return false; }
  }, []);

  const [reduceMotion, setReduceMotion] = useState(() => {
    const saved = localStorage.getItem(LS_KEYS.reduceMotion);
    return saved !== null ? saved === 'true' : osPrefersReduced;
  });
  const [muteAudio, setMuteAudio] = useState(() => {
    const saved = localStorage.getItem(LS_KEYS.muteAudio);
    return saved !== null ? saved === 'true' : false;
  });

  useEffect(() => {
    localStorage.setItem(LS_KEYS.reduceMotion, String(reduceMotion));
    // Toggle a root class for global CSS overrides
    const root = document.documentElement;
    if (reduceMotion) root.classList.add('reduce-motion');
    else root.classList.remove('reduce-motion');
  }, [reduceMotion]);

  useEffect(() => {
    localStorage.setItem(LS_KEYS.muteAudio, String(muteAudio));
  }, [muteAudio]);

  const value = useMemo(() => ({ reduceMotion, setReduceMotion, muteAudio, setMuteAudio }), [reduceMotion, muteAudio]);

  return (
    <SettingsContext.Provider value={value}>
      {children}
    </SettingsContext.Provider>
  );
}

export function useSettings() {
  const ctx = useContext(SettingsContext);
  if (!ctx) throw new Error('useSettings must be used within SettingsProvider');
  return ctx;
}
